import { z } from 'zod'
import { db } from '@/lib/db'
import { auth, handle, instituteOf, json, parse, HttpError, logAction } from '@/lib/api'

export const GET = handle(async (req) => {
  const session = await auth(['INSTITUTE_ADMIN', 'TEACHER', 'PARENT', 'STUDENT'])
  const instituteId = instituteOf(session)
  const url = new URL(req.url)

  let where: any = { instituteId }
  if (session.role === 'PARENT') {
    where.student = { parentId: session.parent?.id }
  } else if (session.role === 'STUDENT') {
    const student = await db.student.findFirst({ where: { userId: session.sub } })
    if (!student) return json([])
    where.studentId = student.id
  }

  const invoices = await db.invoice.findMany({
    where,
    orderBy: { createdAt: 'desc' },
    include: {
      student: { include: { user: { select: { name: true } } } },
      items: true,
      payments: true,
    },
  })
  return json(invoices)
})

const createSchema = z.object({
  studentId: z.string(),
  dueDate: z.string().transform(v => new Date(v)),
  items: z.array(z.object({
    description: z.string(),
    amount: z.number().positive(),
  })).min(1),
})

export const POST = handle(async (req) => {
  const session = await auth(['INSTITUTE_ADMIN', 'TEACHER'])
  const instituteId = instituteOf(session)
  const input = await parse(req, createSchema)

  const student = await db.student.findFirst({ where: { id: input.studentId, instituteId } })
  if (!student) throw new HttpError(404, 'Student not found')

  const totalAmount = input.items.reduce((sum, item) => sum + item.amount, 0)

  const invoice = await db.invoice.create({
    data: {
      instituteId,
      studentId: student.id,
      dueDate: input.dueDate,
      totalAmount,
      status: 'ISSUED',
      items: {
        create: input.items,
      },
    },
    include: { items: true },
  })

  await logAction(instituteId, session.sub, 'CREATE_INVOICE', 'Invoice', invoice.id, `Amount: ${totalAmount}`)
  await db.student.update({ where: { id: student.id }, data: { feeStatus: 'DUE' } })

  return json(invoice, 201)
})

import { z } from 'zod'
import { db } from '@/lib/db'
import { auth, handle, instituteOf, json, parse, HttpError, logAction } from '@/lib/api'

const paySchema = z.object({
  method: z.enum(['CASH', 'ONLINE']),
  note: z.string().optional(),
})

export const POST = handle(async (req, ctx) => {
  const session = await auth(['INSTITUTE_ADMIN', 'TEACHER', 'PARENT', 'STUDENT'])
  const instituteId = instituteOf(session)
  const invoiceId = ctx.params.id
  const input = await parse(req, paySchema)

  const invoice = await db.invoice.findFirst({
    where: { id: invoiceId, instituteId },
    include: { student: true },
  })

  if (!invoice) throw new HttpError(404, 'Invoice not found')
  if (invoice.status === 'PAID') throw new HttpError(400, 'Invoice already paid')

  if (input.method === 'CASH') {
    // Only Admin/Teacher can record cash bypass
    if (!['INSTITUTE_ADMIN', 'TEACHER'].includes(session.role)) {
      throw new HttpError(403, 'Only admins/teachers can record cash payments')
    }

    const payment = await db.$transaction(async (tx) => {
      const p = await tx.feePayment.create({
        data: {
          instituteId,
          studentId: invoice.studentId,
          amount: invoice.totalAmount,
          method: 'CASH',
          invoiceId: invoice.id,
          note: input.note,
          recordedById: session.sub,
        },
      })
      await tx.invoice.update({ where: { id: invoice.id }, data: { status: 'PAID' } })
      await tx.student.update({ where: { id: invoice.studentId }, data: { feeStatus: 'PAID' } })
      return p
    })
    await logAction(instituteId, session.sub, 'PAY_INVOICE_CASH', 'Invoice', invoice.id)
    return json(payment, 201)
  }

  // ONLINE method - mock Stripe checkout integration
  // In a real scenario, we would create a Stripe Checkout Session here and return the URL
  const mockCheckoutUrl = `/dashboard/mock-checkout?invoiceId=${invoice.id}`
  return json({ url: mockCheckoutUrl }, 200)
})

import { db } from '@/lib/db'
import { handle, json, HttpError, logAction } from '@/lib/api'

export const POST = handle(async (req) => {
  // Mock Stripe webhook for testing integration
  // In a real application, we would use `stripe.webhooks.constructEvent` here
  const body = await req.json()

  if (body.type === 'checkout.session.completed') {
    const invoiceId = body.data.object.client_reference_id

    if (!invoiceId) throw new HttpError(400, 'Missing client_reference_id')

    const invoice = await db.invoice.findUnique({ where: { id: invoiceId } })
    if (!invoice || invoice.status === 'PAID') return json({ received: true })

    await db.$transaction(async (tx) => {
      await tx.feePayment.create({
        data: {
          instituteId: invoice.instituteId,
          studentId: invoice.studentId,
          amount: invoice.totalAmount,
          method: 'ONLINE',
          invoiceId: invoice.id,
          note: 'Stripe Checkout',
        },
      })
      await tx.invoice.update({ where: { id: invoice.id }, data: { status: 'PAID', stripeId: body.data.object.id } })
      await tx.student.update({ where: { id: invoice.studentId }, data: { feeStatus: 'PAID' } })
    })

    await logAction(invoice.instituteId, 'system', 'PAY_INVOICE_STRIPE', 'Invoice', invoice.id)
  }

  return json({ received: true })
})

import { z } from 'zod'
import { db } from '@/lib/db'
import { handle, json, parse, HttpError, logAction } from '@/lib/api'
import crypto from 'crypto'

const schema = z.object({
  email: z.string().email(),
})

export const POST = handle(async (req) => {
  const { email } = await parse(req, schema)
  const user = await db.user.findUnique({ where: { email } })

  if (!user) {
    // Return 200 anyway to prevent email enumeration
    return json({ ok: true })
  }

  const token = crypto.randomBytes(32).toString('hex')
  const expiresAt = new Date()
  expiresAt.setHours(expiresAt.getHours() + 1) // 1 hour expiry

  await db.passwordResetToken.create({
    data: {
      userId: user.id,
      token,
      expiresAt,
    },
  })

  // In a real application, send an email here with the link:
  // https://yourdomain.com/reset-password?token=${token}
  console.log(`[EMAIL MOCK] Password reset link for ${email}: /reset-password?token=${token}`)

  if (user.instituteId) {
    await logAction(user.instituteId, user.id, 'REQUEST_PASSWORD_RESET', 'User', user.id)
  }

  return json({ ok: true })
})

