import { z } from 'zod'
import { db } from '@/lib/db'
import { hashPassword, getSession } from '@/lib/auth'
import { handle, json, parse, HttpError } from '@/lib/api'

const schema = z.object({
  email: z.string().email().optional(),
  token: z.string().optional(),
  newPassword: z.string().min(6),
})

export const POST = handle(async (req) => {
  const { email, token, newPassword } = await parse(req, schema)

  if (token) {
    // Token-based user-initiated reset
    const resetToken = await db.passwordResetToken.findUnique({
      where: { token },
      include: { user: true },
    })

    if (!resetToken || resetToken.expiresAt < new Date()) {
      throw new HttpError(400, 'Invalid or expired token')
    }

    await db.user.update({
      where: { id: resetToken.userId },
      data: { passwordHash: await hashPassword(newPassword) }
    })

    await db.passwordResetToken.delete({ where: { id: resetToken.id } })
    return json({ ok: true })
  }

  // Admin-initiated reset
  if (!email) throw new HttpError(400, 'Email or token is required')

  const session = await getSession()
  if (!session || !['SUPER_ADMIN', 'INSTITUTE_ADMIN'].includes(session.role)) {
    throw new HttpError(403, 'Forbidden')
  }

  const target = await db.user.findUnique({ where: { email } })
  if (!target) throw new HttpError(404, 'User not found')

  if (session.role === 'INSTITUTE_ADMIN') {
    if (!target.instituteId || target.instituteId !== session.instituteId) {
      throw new HttpError(403, 'You can only reset passwords for users in your institute')
    }
  }

  await db.user.update({ where: { id: target.id }, data: { passwordHash: await hashPassword(newPassword) } })
  return json({ ok: true })
})

