import { z } from 'zod'
import { db } from '@/lib/db'
import { auth, handle, instituteOf, json, parse, HttpError, logAction } from '@/lib/api'
import { hashPassword } from '@/lib/auth'
import { GoogleGenAI } from '@google/genai'

const ai = new GoogleGenAI({ apiKey: process.env.GEMINI_API_KEY || 'dummy-key' })

const importSchema = z.object({
  csvData: z.string(),
  batchIds: z.array(z.string()).default([]),
})

export const POST = handle(async (req) => {
  const session = await auth(['INSTITUTE_ADMIN', 'TEACHER'])
  const instituteId = instituteOf(session)
  const input = await parse(req, importSchema)

  // Use Gemini to map arbitrary CSV data to our schema
  let parsedStudents: any[] = []
  try {
    const prompt = `
      You are an expert data extraction assistant.
      The following is CSV data containing student information. The columns might be named anything.
      Map the data into a JSON array of objects with the exact following schema:
      {
        "name": string (the student's name),
        "email": string (must be valid email. If none, generate \`<firstname>.<lastname>@temp.local\`),
        "phone": string (optional, just digits),
        "guardianName": string (optional, parent or guardian name),
        "guardianPhone": string (optional, parent/guardian phone number)
      }

      Only return the raw JSON array. No markdown blocks, no extra text.

      CSV DATA:
      ${input.csvData}
    `

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    })

    const rawText = response.text || '[]'
    const jsonMatch = rawText.match(/\[.*\]/s)
    parsedStudents = JSON.parse(jsonMatch ? jsonMatch[0] : rawText)
  } catch (error) {
    console.error('AI Parsing failed:', error)
    throw new HttpError(400, 'Failed to parse the provided CSV data using AI.')
  }

  if (!Array.isArray(parsedStudents) || parsedStudents.length === 0) {
    throw new HttpError(400, 'No valid students found in the parsed data.')
  }

  let importedCount = 0
  for (const stu of parsedStudents) {
    // Skip if email exists
    const exists = await db.user.findUnique({ where: { email: stu.email } })
    if (exists) continue

    const user = await db.user.create({
      data: {
        email: stu.email,
        name: stu.name,
        phone: stu.phone || null,
        role: 'STUDENT',
        passwordHash: await hashPassword('changeme123'),
        instituteId,
        student: {
          create: {
            instituteId,
            guardianName: stu.guardianName || null,
            guardianPhone: stu.guardianPhone || null,
          },
        },
      },
      include: { student: true },
    })

    if (input.batchIds.length && user.student) {
      await db.batchStudent.createMany({
        data: input.batchIds.map((batchId) => ({ batchId, studentId: user.student!.id })),
      })
    }
    importedCount++
  }

  await logAction(instituteId, session.sub, 'IMPORT_STUDENTS', 'Student', undefined, `Imported ${importedCount} students via AI parsing.`)

  return json({ message: `Successfully imported ${importedCount} students.`, importedCount }, 201)
})

