import { db } from '@/lib/db'
import { auth, handle, instituteOf, json } from '@/lib/api'

export const GET = handle(async (req) => {
  const session = await auth(['INSTITUTE_ADMIN', 'TEACHER'])
  const instituteId = instituteOf(session)

  // Find students at risk based on:
  // 1. Low attendance (< 75%)
  // 2. Low marks average (< 50%)

  const students = await db.student.findMany({
    where: { instituteId },
    include: {
      user: { select: { name: true, phone: true } },
      attendance: true,
      marks: { include: { exam: { select: { maxMarks: true } } } },
    }
  })

  const atRisk = []

  for (const s of students) {
    let riskFactors = []

    // Calculate Attendance Risk
    const totalSessions = s.attendance.length
    if (totalSessions > 0) {
      const present = s.attendance.filter(a => a.status === 'PRESENT').length
      const late = s.attendance.filter(a => a.status === 'LATE').length
      const attendancePct = Math.round(((present + late) / totalSessions) * 100)
      if (attendancePct < 75) {
        riskFactors.push(`Low Attendance (${attendancePct}%)`)
      }
    }

    // Calculate Marks Risk
    let totalScore = 0
    let totalMax = 0
    for (const m of s.marks) {
      totalScore += m.score
      totalMax += m.exam.maxMarks
    }

    if (totalMax > 0) {
      const scorePct = Math.round((totalScore / totalMax) * 100)
      if (scorePct < 50) {
        riskFactors.push(`Low Grades (${scorePct}%)`)
      }
    }

    if (riskFactors.length > 0) {
      atRisk.push({
        studentId: s.id,
        name: s.user.name,
        guardianName: s.guardianName,
        guardianPhone: s.guardianPhone,
        riskFactors,
      })
    }
  }

  return json({ atRisk })
})

