import { useEffect, useState } from 'react'
import { api } from '@/lib/client'

export default function ParentDashboard() {
  const [invoices, setInvoices] = useState<any[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    api('/api/invoices')
      .then(setInvoices)
      .catch(console.error)
      .finally(() => setLoading(false))
  }, [])

  if (loading) return <div className="skeleton" style={{ height: 200 }} />

  return (
    <>
      <h1>Parent Dashboard</h1>
      <div className="card">
        <h2>💳 Fee Invoices</h2>
        {invoices.length === 0 ? (
          <p className="muted">No invoices found.</p>
        ) : (
          <table>
            <thead>
              <tr>
                <th>Date</th>
                <th>Student</th>
                <th>Amount</th>
                <th>Status</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {invoices.map((inv) => (
                <tr key={inv.id}>
                  <td>{new Date(inv.dueDate).toLocaleDateString()}</td>
                  <td>{inv.student?.user?.name}</td>
                  <td>${inv.totalAmount}</td>
                  <td>
                    <span className={`badge ${inv.status === 'PAID' ? 'green' : 'red'}`}>
                      {inv.status}
                    </span>
                  </td>
                  <td>
                    {inv.status !== 'PAID' && (
                      <button 
                        className="btn sm"
                        onClick={async () => {
                          const res = await api(`/api/invoices/${inv.id}/pay`, {
                            method: 'POST',
                            body: JSON.stringify({ method: 'ONLINE' })
                          })
                          if (res.url) window.location.href = res.url
                        }}
                      >
                        Pay Online
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </>
  )
}

