export const GET = handle(async () => {
  await auth(['SUPER_ADMIN'])
  const [institutes, platformPayments, attendance, batches, students, studentFees] = await Promise.all([
    db.institute.findMany({ select: { id: true, name: true, status: true } }),
    db.payment.findMany({ select: { amount: true, periodMonth: true, instituteId: true } }),
    db.attendance.groupBy({ by: ['batchId', 'status'], _count: { _all: true } }),
    db.batch.findMany({ select: { id: true, instituteId: true } }),
    db.student.count(),
    db.feePayment.aggregate({ _sum: { amount: true } }),
  ])

  const byMonth: Record<string, number> = {}
  for (const p of platformPayments) byMonth[p.periodMonth] = (byMonth[p.periodMonth] ?? 0) + p.amount

  const batchInstitute = new Map(batches.map((b) => [b.id, b.instituteId]))
  const att: Record<string, { present: number; total: number }> = {}
  for (const a of attendance) {
    const instId = batchInstitute.get(a.batchId)
    if (!instId) continue
    if (!att[instId]) att[instId] = { present: 0, total: 0 }
    att[instId].total += a._count._all
    if (a.status !== 'ABSENT') att[instId].present += a._count._all
  }

  return json({
    totalInstitutes: institutes.length,
    activeInstitutes: institutes.filter((i) => i.status === 'ACTIVE').length,
    totalPlatformRevenue: platformPayments.reduce((s, p) => s + p.amount, 0),
    totalStudentRevenue: studentFees._sum.amount ?? 0,
    totalStudents: students,
    revenueByMonth: Object.entries(byMonth)
      .sort()
      .map(([month, amount]) => ({ month, amount })),
    attendanceByInstitute: institutes.map((i) => ({
      id: i.id,
      name: i.name,
      rate: att[i.id] && att[i.id].total > 0 ? Math.round((att[i.id].present / att[i.id].total) * 100) : null,
    })),
  })
})

