import { z } from 'zod'
import { db } from '@/lib/db'
import { auth, handle, json, parse, HttpError } from '@/lib/api'

const schema = z.object({
  amount: z.number().positive(),
  periodMonth: z.string().regex(/^\d{4}-\d{2}$/),
})

export const POST = handle(async (req, ctx) => {
  await auth(['SUPER_ADMIN'])
  const instituteId = ctx.params.id
  const { amount, periodMonth } = await parse(req, schema)

  const institute = await db.institute.findUnique({ where: { id: instituteId } })
  if (!institute) throw new HttpError(404, 'Institute not found')

  const payment = await db.payment.create({
    data: {
      instituteId,
      amount,
      periodMonth,
    },
  })

  return json(payment, 201)
})

