import { z } from 'zod'
import { db } from '@/lib/db'
import { hashPassword } from '@/lib/auth'
import { handle, json, parse, HttpError } from '@/lib/api'

const schema = z.object({
  joinCode: z.string(),
  name: z.string().min(2),
  email: z.string().email(),
  password: z.string().min(6),
  phone: z.string().optional(),
  guardianName: z.string().optional(),
  guardianPhone: z.string().optional(),
})

export const POST = handle(async (req) => {
  const input = await parse(req, schema)

  // Find batch by join code
  const batch = await db.batch.findUnique({
    where: { joinCode: input.joinCode },
    include: { _count: { select: { students: true } } }
  })

  if (!batch) throw new HttpError(404, 'Invalid batch code')
  if (batch._count.students >= batch.capacity) {
    throw new HttpError(400, 'This batch is already at full capacity')
  }

  // Check if user exists
  const exists = await db.user.findUnique({ where: { email: input.email } })
  if (exists) throw new HttpError(400, 'Email already registered. Please login and join from your dashboard.')

  // Create user and student
  const user = await db.user.create({
    data: {
      email: input.email,
      name: input.name,
      phone: input.phone,
      role: 'STUDENT',
      passwordHash: await hashPassword(input.password),
      instituteId: batch.instituteId,
      student: {
        create: {
          instituteId: batch.instituteId,
          guardianName: input.guardianName,
          guardianPhone: input.guardianPhone,
          enrollments: {
            create: {
              batchId: batch.id
            }
          }
        },
      },
    },
  })

  return json({ message: 'Successfully enrolled!', batchName: batch.name }, 201)
})

'use client'

import { useState, useEffect } from 'react'
import { api } from '@/lib/client'
import Link from 'next/link'

export default function PublicEnrollment() {
  const [form, setForm] = useState({
    joinCode: '',
    name: '',
    email: '',
    password: '',
    phone: '',
    guardianName: '',
    guardianPhone: '',
  })
  const [loading, setLoading] = useState(false)
  const [message, setMessage] = useState('')
  const [error, setError] = useState('')

  useEffect(() => {
    const params = new URLSearchParams(window.location.search)
    const code = params.get('code')
    if (code) setForm(prev => ({ ...prev, joinCode: code }))
  }, [])

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setLoading(true)
    setError('')
    setMessage('')
    try {
      const res = await api('/api/enroll', {
        method: 'POST',
        body: JSON.stringify(form)
      })
      setMessage(res.message)
      setForm({ joinCode: '', name: '', email: '', password: '', phone: '', guardianName: '', guardianPhone: '' })
    } catch (err: any) {
      setError(err.message)
    }
    setLoading(false)
  }

  const set = (k: string) => (e: any) => setForm({ ...form, [k]: e.target.value })

  return (
    <main className="container" style={{ maxWidth: 500, marginTop: 40 }}>
      <div className="card">
        <h1 style={{ textAlign: 'center' }}>🎓 Student Enrollment</h1>
        <p className="muted" style={{ textAlign: 'center', marginBottom: 20 }}>
          Enter your details and batch code to join.
        </p>

        {message ? (
          <div className="success" style={{ textAlign: 'center', padding: 20 }}>
            <h2>{message}</h2>
            <p>You can now login to your dashboard.</p>
            <Link href="/login" className="btn" style={{ marginTop: 20, display: 'inline-block' }}>Go to Login</Link>
          </div>
        ) : (
          <form onSubmit={handleSubmit}>
            <div style={{ marginBottom: 15 }}>
              <label>Batch Code</label>
              <input 
                placeholder="e.g. MATH123" 
                value={form.joinCode} 
                onChange={set('joinCode')} 
                required 
                style={{ width: '100%' }}
              />
            </div>

            <div className="grid cols-2" style={{ gap: 15 }}>
              <div>
                <label>Your Name</label>
                <input value={form.name} onChange={set('name')} required style={{ width: '100%' }} />
              </div>
              <div>
                <label>Email</label>
                <input type="email" value={form.email} onChange={set('email')} required style={{ width: '100%' }} />
              </div>
            </div>

            <div style={{ marginBottom: 15, marginTop: 15 }}>
              <label>Password (min 6 chars)</label>
              <input type="password" value={form.password} onChange={set('password')} required minLength={6} style={{ width: '100%' }} />
            </div>

            <div style={{ marginBottom: 15 }}>
              <label>Phone (Optional)</label>
              <input value={form.phone} onChange={set('phone')} style={{ width: '100%' }} />
            </div>

            <hr style={{ margin: '20px 0', border: 0, borderTop: '1px solid #eee' }} />
            <p style={{ fontWeight: 'bold', fontSize: 14 }}>Guardian Information</p>

            <div className="grid cols-2" style={{ gap: 15, marginTop: 10 }}>
              <div>
                <label>Name</label>
                <input value={form.guardianName} onChange={set('guardianName')} style={{ width: '100%' }} />
              </div>
              <div>
                <label>Phone</label>
                <input value={form.guardianPhone} onChange={set('guardianPhone')} style={{ width: '100%' }} />
              </div>
            </div>

            <button 
              className="btn" 
              style={{ width: '100%', marginTop: 25 }} 
              disabled={loading}
            >
              {loading ? 'Joining...' : 'Register & Join Batch'}
            </button>

            {error && <p className="error" style={{ marginTop: 15, textAlign: 'center' }}>{error}</p>}
          </form>
        )}
      </div>
    </main>
  )
}

