import { cuid } from '@paralleldrive/cuid2' // Or just use a random string if cuid2 isn't available

const db = new PrismaClient()

async function main() {
  const batches = await db.batch.findMany({ where: { joinCode: null } })
  console.log(`Found ${batches.length} batches without join codes.`)

  for (const b of batches) {
    const code = Math.random().toString(36).substring(2, 8).toUpperCase()
    await db.batch.update({
      where: { id: b.id },
      data: { joinCode: code }
    })
    console.log(`Assigned code ${code} to batch: ${b.name}`)
  }

  console.log('Done.')
}

main().finally(() => db.$disconnect())

