          <div>
            <label style={{ marginBottom: 10 }}>Mark fee status paid</label>
            <input
              type="checkbox"
              checked={form.markPaid}
              onChange={(e) => setForm({ ...form, markPaid: e.target.checked })}
              style={{ width: 20, height: 20 }}
            />
          </div>
