        method: 'POST',
        body: JSON.stringify({
          studentId: form.studentId,
          amount: Number(form.amount),
          note: form.note || undefined,
          markPaid: form.markPaid,
        }),
      })
      setForm(emptyForm)
      setSaved('Payment recorded ✓')
      setPage(1)
      await load(1)
    } catch (err: any) { setError(err.message) }
    setBusy(false)
  }

