              <tbody>
                {data.items.map((p: any) => (
                  <tr key={p.id}>
                    <td className="muted">{new Date(p.paidAt).toLocaleString()}</td>
                    <td><strong>{p.student.user.name}</strong></td>
                    <td><span className="badge green">{money(p.amount)}</span></td>
                    <td className="muted">{p.note || '-'}</td>
