import { SignJWT, jwtVerify } from 'jose'
import bcrypt from 'bcryptjs'
import { cookies } from 'next/headers'

const secret = new TextEncoder().encode(process.env.JWT_SECRET ?? 'dev-secret-change-me')

export type Role = 'SUPER_ADMIN' | 'INSTITUTE_ADMIN' | 'TEACHER' | 'STUDENT'

export interface Session {
  sub: string
  name: string
  role: Role
  instituteId: string | null
  [key: string]: unknown
}

export async function signToken(session: Session): Promise<string> {
  return new SignJWT(session)
    .setProtectedHeader({ alg: 'HS256' })
    .setIssuedAt()
    .setExpirationTime('12h')
    .sign(secret)
}

export async function getSession(): Promise<Session | null> {
  const token = cookies().get('token')?.value
  if (!token) return null
  try {
    const { payload } = await jwtVerify(token, secret)
    return payload as unknown as Session
  } catch {
    return null
  }
}

export const hashPassword = (plain: string) => bcrypt.hash(plain, 10)
export const verifyPassword = (plain: string, hashed: string) => bcrypt.compare(plain, hashed)

import { z } from 'zod'
import { db } from '@/lib/db'
import { auth, handle, instituteOf, json, parse, HttpError, logAction } from '@/lib/api'

export const GET = handle(async (req) => {
  const session = await auth(['INSTITUTE_ADMIN', 'TEACHER', 'PARENT', 'STUDENT'])
  const instituteId = instituteOf(session)

  let where: any = { instituteId }

  if (session.role === 'PARENT') {
    // SECURITY: Ensure parent can only see their children's invoices
    where.student = { userId: null } // fallback to empty
    const parent = await db.parent.findFirst({ where: { userId: session.sub } })
    if (parent) {
      where.student = { parentId: parent.id }
    }
  } else if (session.role === 'STUDENT') {
    // SECURITY: Ensure student can only see their own invoices
    where.student = { userId: session.sub }
  }

  const invoices = await db.invoice.findMany({
    where,
    orderBy: { createdAt: 'desc' },
    include: {
      student: { include: { user: { select: { name: true } } } },
      items: true,
      payments: true,
    },
  })
  return json(invoices)
})

const createSchema = z.object({
  studentId: z.string(),
  dueDate: z.string().transform(v => new Date(v)),
  items: z.array(z.object({
    description: z.string(),
    amount: z.number().positive(),
  })).min(1),
})

export const POST = handle(async (req) => {
  const session = await auth(['INSTITUTE_ADMIN', 'TEACHER'])
  const instituteId = instituteOf(session)
  const input = await parse(req, createSchema)

  const student = await db.student.findFirst({ where: { id: input.studentId, instituteId } })
  if (!student) throw new HttpError(404, 'Student not found')

  const totalAmount = input.items.reduce((sum, item) => sum + item.amount, 0)

  const invoice = await db.invoice.create({
    data: {
      instituteId,
      studentId: student.id,
      dueDate: input.dueDate,
      totalAmount,
      status: 'ISSUED',
      items: {
        create: input.items,
      },
    },
    include: { items: true },
  })

  await logAction(instituteId, session.sub, 'CREATE_INVOICE', 'Invoice', invoice.id, `Amount: ${totalAmount}`)
  await db.student.update({ where: { id: student.id }, data: { feeStatus: 'DUE' } })

  return json(invoice, 201)
})

import { NextRequest, NextResponse } from 'next/server'
import type { ZodSchema } from 'zod'
import { getSession, Role, Session } from './auth'

export class HttpError extends Error {
  constructor(public status: number, message: string) {
    super(message)
  }
}

export function json(data: unknown, status = 200) {
  return NextResponse.json(data, { status })
}

export async function auth(roles?: Role[]): Promise<Session> {
  const session = await getSession()
  if (!session) throw new HttpError(401, 'Unauthorized')
  if (roles && !roles.includes(session.role)) throw new HttpError(403, 'Forbidden')
  return session
}

export function instituteOf(session: Session): string {
  if (!session.instituteId) throw new HttpError(403, 'No institute scope')
  return session.instituteId
}

export async function parse<T>(req: NextRequest, schema: ZodSchema<T>): Promise<T> {
  const body = await req.json().catch(() => {
    throw new HttpError(400, 'Invalid JSON body')
  })
  const result = schema.safeParse(body)
  if (!result.success) {
    throw new HttpError(400, result.error.errors.map((e) => `${e.path.join('.')}: ${e.message}`).join('; '))
  }
  return result.data
}

type Handler = (req: NextRequest, ctx: any) => Promise<NextResponse>

export function handle(fn: Handler): Handler {
  return async (req, ctx) => {
    try {
      return await fn(req, ctx)
    } catch (e) {
      if (e instanceof HttpError) return json({ error: e.message }, e.status)
      console.error(e)
      return json({ error: 'Internal server error' }, 500)
    }
  }
}

export function csvResponse(filename: string, rows: (string | number)[][]) {
  const csv = rows.map((r) => r.map((c) => `"${String(c).replace(/"/g, '""')}"`).join(',')).join('\n')
  return new NextResponse(csv, {
    headers: {
      'Content-Type': 'text/csv',
      'Content-Disposition': `attachment; filename="${filename}"`,
    },
  })
}

export async function logAction(instituteId: string, userId: string, action: string, entity: string, entityId?: string, details?: string) {
  try {
    const { db } = await import('./db')
    await db.auditLog.create({
      data: { instituteId, userId, action, entity, entityId, details },
    })
  } catch (e) {
    console.error('Failed to write audit log', e)
  }
}

