import { hashPassword } from '@/lib/auth'
import { GoogleGenAI } from '@google/genai'

const ai = new GoogleGenAI({ apiKey: process.env.GEMINI_API_KEY || 'dummy-key' })

const importSchema = z.object({
  csvData: z.string(),
  batchIds: z.array(z.string()).default([]),
})

export const POST = handle(async (req) => {
  const session = await auth(['INSTITUTE_ADMIN', 'TEACHER'])
  const instituteId = instituteOf(session)
  const input = await parse(req, importSchema)

  // Use Gemini to map arbitrary CSV data to our schema
  let parsedStudents: any[] = []
  try {
    const prompt = `
      You are an expert data extraction assistant.
      The following is CSV data containing student information. The columns might be named anything.
      Map the data into a JSON array of objects with the exact following schema:
      {
        "name": string (the student's name),
        "email": string (must be valid email. If none, generate \`<firstname>.<lastname>@temp.local\`),
        "phone": string (optional, just digits),
        "guardianName": string (optional, parent or guardian name),
        "guardianPhone": string (optional, parent/guardian phone number)
      }

      Only return the raw JSON array. No markdown blocks, no extra text.

      CSV DATA:
      ${input.csvData}
    `

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    })

    const rawText = response.text || '[]'
    const jsonMatch = rawText.match(/\[[\s\S]*\]/)
    parsedStudents = JSON.parse(jsonMatch ? jsonMatch[0] : rawText)
  } catch (error) {
    console.error('AI Parsing failed:', error)
    throw new HttpError(400, 'Failed to parse the provided CSV data using AI.')
  }

