            guardianName: stu.guardianName || null,
            guardianPhone: stu.guardianPhone || null,
          },
        },
      },
      include: { student: true },
    })

    if (input.batchIds.length && user.student) {
      await db.batchStudent.createMany({
        data: input.batchIds.map((batchId) => ({ batchId, studentId: user.student!.id })),
      })
    }
    importedCount++
