export const POST = handle(async (req) => {
  await auth(['SUPER_ADMIN'])
  const input = await parse(req, onboardSchema)
  const exists = await db.user.findUnique({ where: { email: input.adminEmail } })
  if (exists) throw new HttpError(400, 'Admin email already in use')
  const passwordHash = await hashPassword(input.adminPassword)

  const joinCode = Math.random().toString(36).substring(2, 8).toUpperCase()

  const institute = await db.$transaction(async (tx) => {
    const inst = await tx.institute.create({
      data: { 
        name: input.name, 
        email: input.email, 
        phone: input.phone, 
        plan: input.plan, 
        monthlyFee: input.monthlyFee,
        joinCode
      },
    })
    await tx.user.create({
      data: { email: input.adminEmail, name: input.adminName, role: 'INSTITUTE_ADMIN', passwordHash, instituteId: inst.id },
    })
    const monthlyFee = input.monthlyFee ?? 0
    if (monthlyFee > 0) {
      await tx.payment.create({
        data: { instituteId: inst.id, amount: monthlyFee, periodMonth: new Date().toISOString().slice(0, 7) },
      })
    }
    return inst
  })
  return json(institute, 201)
})

