const schema = z.object({
  joinCode: z.string(), // Can be Institute code OR Batch code
  name: z.string().min(2),
  email: z.string().email(),
  password: z.string().min(6),
  phone: z.string().optional(),
  guardianName: z.string().optional(),
  guardianPhone: z.string().optional(),
})

export const POST = handle(async (req) => {
  const input = await parse(req, schema)

  // Find institute by join code
  let institute = await db.institute.findUnique({
    where: { joinCode: input.joinCode }
  })

  let batch = null

  // If not an institute code, try batch code
  if (!institute) {
    batch = await db.batch.findUnique({
      where: { joinCode: input.joinCode },
      include: { _count: { select: { students: true } } }
    })

    if (batch) {
      institute = await db.institute.findUnique({ where: { id: batch.instituteId } })
    }
  }

  if (!institute) throw new HttpError(404, 'Invalid code. Please check your Institute or Batch code.')

  if (batch && batch._count.students >= batch.capacity) {
    throw new HttpError(400, 'This batch is already at full capacity')
  }

  // Check if user exists
  const exists = await db.user.findUnique({ where: { email: input.email } })
  if (exists) throw new HttpError(400, 'Email already registered. Please login and join from your dashboard.')

  // Create user and student
  const user = await db.user.create({
    data: {
      email: input.email,
      name: input.name,
      phone: input.phone,
      role: 'STUDENT',
      passwordHash: await hashPassword(input.password),
      instituteId: institute.id,
      student: {
        create: {
          instituteId: institute.id,
          guardianName: input.guardianName,
          guardianPhone: input.guardianPhone,
          ...(batch ? {
            enrollments: {
              create: {
                batchId: batch.id
              }
            }
          } : {})
        },
      },
    },
  })

  const targetName = batch ? `Batch ${batch.name}` : `${institute.name}`
  return json({ message: 'Successfully enrolled!', targetName }, 201)
})

