import { db } from './db'
import { HttpError } from './api'

/**
 * Basic database-backed rate limiter for serverless environments.
 * @param key The unique key to rate limit (e.g., `login:${ip}`)
 * @param maxAttempts Maximum allowed attempts within the window
 * @param windowMs Time window in milliseconds
 */
export async function checkRateLimit(key: string, maxAttempts: number, windowMs: number) {
  const now = new Date()

  // Cleanup expired entries occasionally (could be a cron job, but we'll do it inline for simplicity)
  // await db.rateLimit.deleteMany({ where: { expiresAt: { lt: now } } }).catch(() => {})

  const limit = await db.rateLimit.findUnique({
    where: { key },
  })

  if (limit) {
    if (limit.expiresAt < now) {
      // Expired, reset
      await db.rateLimit.update({
        where: { key },
        data: {
          count: 1,
          expiresAt: new Date(now.getTime() + windowMs),
        },
      })
      return
    }

    if (limit.count >= maxAttempts) {
      const waitMinutes = Math.ceil((limit.expiresAt.getTime() - now.getTime()) / 60000)
      throw new HttpError(429, `Too many attempts. Please try again in ${waitMinutes} minutes.`)
    }

    await db.rateLimit.update({
      where: { key },
      data: { count: { increment: 1 } },
    })
  } else {
    // New entry
    await db.rateLimit.create({
      data: {
        key,
        count: 1,
        expiresAt: new Date(now.getTime() + windowMs),
      },
    })
  }
}

