import { db } from '@/lib/db'
import { auth, handle, json, HttpError } from '@/lib/api'

export const POST = handle(async (req) => {
  const session = await auth(['INSTITUTE_ADMIN', 'TEACHER'])

  const institute = await db.institute.findUnique({
    where: { id: session.instituteId! },
    select: { whatsappToken: true, whatsappPhoneId: true }
  })

  if (!institute || !institute.whatsappToken || !institute.whatsappPhoneId) {
    throw new HttpError(400, 'WhatsApp API is not configured for this institute.')
  }

  const token = institute.whatsappToken
  const phoneId = institute.whatsappPhoneId

  // Fetch up to 50 pending notifications for this institute
  const pending = await db.notificationQueue.findMany({
    where: { instituteId: session.instituteId!, status: 'PENDING' },
    take: 50
  })

  if (pending.length === 0) {
    return json({ message: 'No pending alerts.' })
  }

  let successCount = 0
  let failCount = 0

  for (const notif of pending) {
    try {
      const payloadObj = JSON.parse(notif.payload)
      let finalParams: any[] = []
      let templateName = ''

      if (notif.type === 'ABSENT') {
        templateName = 'absent_alert' // replace with your actual meta template
        finalParams = [
          { type: 'text', text: payloadObj.studentName },
          { type: 'text', text: payloadObj.date }
        ]
      } else if (notif.type === 'MARKS') {
        templateName = 'marks_update' // replace with your actual meta template
        finalParams = [
          { type: 'text', text: payloadObj.studentName },
          { type: 'text', text: String(payloadObj.score) },
          { type: 'text', text: payloadObj.examName },
          { type: 'text', text: String(payloadObj.maxMarks) }
        ]
      }

      const metaPayload = {
        messaging_product: 'whatsapp',
        to: notif.recipient,
        type: 'template',
        template: {
          name: templateName,
          language: { code: 'en' },
          components: [
            {
              type: 'body',
              parameters: finalParams,
            }
          ],
        },
      }

      const metaRes = await fetch(`https://graph.facebook.com/v19.0/${phoneId}/messages`, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(metaPayload),
      })

      if (metaRes.ok) {
        await db.notificationQueue.update({
          where: { id: notif.id },
          data: { status: 'SENT' }
        })
        successCount++
      } else {
        const errorData = await metaRes.json()
        console.error('Meta API Error:', errorData)
        await db.notificationQueue.update({
          where: { id: notif.id },
          data: { status: 'FAILED' }
        })
        failCount++
      }
    } catch (err) {
      console.error('Failed to process notification:', err)
      failCount++
    }
  }

  return json({ message: `Sent ${successCount} alerts. Failed: ${failCount}.` })
})

